from __future__ import annotations
import ast
from pathlib import Path

SKIP_PARTS={'.git','__pycache__','.venv','venv','node_modules','archive'}
SCAN_ROOTS=[Path('governance/runners'),Path('governance/validators'),Path('scripts'),Path('runtime'),Path('runners')]

def is_skipped(path:Path)->bool:
    return any(part in SKIP_PARTS for part in path.parts) or 'governance/codex' in str(path)

def validate_file(path:Path)->list[str]:
    errors=[]
    text=path.read_text(encoding='utf-8',errors='replace')
    nonblank=[line for line in text.splitlines() if line.strip()]
    if len(text.encode('utf-8'))<50 or len(nonblank)<=4:
        errors.append(f'{path}: truncated python file')
    try:
        tree=ast.parse(text)
    except SyntaxError as exc:
        errors.append(f'{path}: SyntaxError {exc}')
        return errors
    is_runner='runner' in path.name.lower() or 'governance/runners' in str(path)
    if is_runner:
        has_main=any(isinstance(node,ast.FunctionDef) and node.name=='main' for node in tree.body)
        if not has_main:
            errors.append(f'{path}: runner missing def main()')
        if '__main__' not in text:
            errors.append(f'{path}: runner missing __main__ entrypoint')
    return errors

def main()->int:
    checked=[]; errors=[]
    for root in SCAN_ROOTS:
        if not root.exists():
            continue
        for path in root.rglob('*.py'):
            if is_skipped(path):
                continue
            checked.append(str(path))
            errors.extend(validate_file(path))
    if not checked:
        print('BLOCKED: no python files checked')
        return 2
    if errors:
        print('\n'.join(errors))
        return 1
    print(f'PASS: checked {len(checked)} python files')
    return 0

if __name__=='__main__':
    raise SystemExit(main())

